// Parse XML and find first .md or .docx file (not already a linkedin_post)
const xml = $input.item.json.data;
const responsePattern = /<d:response>([\s\S]*?)<\/d:response>/g;
const files = [];
let match;

while ((match = responsePattern.exec(xml)) !== null) {
  const responseBlock = match[1];
  const hrefMatch = responseBlock.match(/<d:href>(.*?)<\/d:href>/);
  if (!hrefMatch) continue;

  const href = hrefMatch[1];
  const isFolder = responseBlock.includes('<d:collection');
  const filename = href.split('/').pop();

  // Skip folders, skip files that are already linkedin posts
  if (!isFolder && 
      (href.endsWith('.md') || href.endsWith('.docx')) &&
      !filename.startsWith('linkedin_post')) {
    files.push({
      href,
      filename,
      downloadUrl: 'https://nextcloud.local.example.home' + href
    });
  }
}

if (files.length === 0) {
  throw new Error('No source documents found in Pending_Review folder. Add some documents there to process!');
}

// Select first file
const selectedFile = files[0];
console.log(`Found ${files.length} source document(s). Selected: ${selectedFile.filename}`);

return {
  selectedFile: selectedFile.href,
  filename: selectedFile.filename,
  downloadUrl: selectedFile.downloadUrl,
  totalAvailable: files.length
};

// Extract file content
const fileContent = $input.item.binary?.data ? 
  Buffer.from($input.item.binary.data.data, 'base64').toString('utf-8') :
  $input.item.json.data || '';

if (!fileContent || fileContent.length < 50) {
  throw new Error('File content is empty or too short. Make sure the source document has content.');
}

console.log(`Extracted ${fileContent.length} characters of content`);

return {
  ...$json,
  fileContent: fileContent.substring(0, 15000), // Limit to 15k chars for Claude
  contentLength: fileContent.length
};

// Extract the post content from Claude's response
const response = $json;
const postContent = response.content?.[0]?.text || '';

if (!postContent) {
  throw new Error('Claude did not return any content');
}

console.log(`Generated post: ${postContent.length} characters`);

return {
  ...$input.item.json,
  generatedPost: postContent,
  postLength: postContent.length,
  timestamp: new Date().toISOString(),
  sourceFilename: $('Find Source Document').item.json.filename
};
